-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft') تحت
-- "أصول الفقه" (usul-fiqh) — تغطي 9 تصنيفات فرعية من أصل 22 (الـ13
-- الباقية منشورة سابقًا): الحكم الشرعي بقسميه، الأدلة المتفق عليها،
-- الأدلة المختلف فيها، دلالات الألفاظ، النسخ، التعارض والترجيح،
-- الاجتهاد والتقليد والفتوى، تحقيق المناط، القواعد الأصولية.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب الدروس الـ13 المنشورة سابقًا في هذا
-- العنقود (تعريفي موجز: قسم body + قسم examples، بلا استشهاد حديثي،
-- مع مثال قرآني حرفي عند الحاجة)، مبني على مصادر أصول الفقه المعتمدة:
-- الوجيز في أصول الفقه لوهبة الزحيلي، أصول الفقه لمحمد أبو زهرة، روضة
-- الناظر لابن قدامة، إرشاد الفحول للشوكاني.
-- الآيات المستشهَد بها (النساء: 59، يوسف: 82، البقرة: 240، البقرة: 234)
-- تحقَّقت حرفياً من artifacts/majalis/public/data/quran محلياً عبر حقل
-- numberInSurah قبل الإدراج.
-- لم يُستشهَد بأي حديث في هذه الدفعة: حديث معاذ بن جبل الشائع في كتب
-- الأصول عن الاجتهاد ("أجتهد رأيي ولا آلو") تبيّن عبر WebSearch أن
-- إسناده محل خلاف قوي بين العلماء (مرسل عند بعضهم، وضعّفه الألباني
-- سندًا ومتنًا)، فلم يستوفِ شرط "صحيح مصرَّح بدرجته بدقة"، فاستُبعد.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات التسعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الحكم الشرعي بقسميه
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='98e7704f-ee12-42c9-9f7a-f6cb7f6be325' AND title='الحكم الشرعي: تعريفه وأقسامه التكليفي والوضعي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الحكم الشرعي: تعريفه وأقسامه التكليفي والوضعي', 'تعريف موجز بالحكم الشرعي وأقسامه الرئيسة: التكليفي والوضعي', '98e7704f-ee12-42c9-9f7a-f6cb7f6be325', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف الحكم الشرعي وأقسامه', 'الحكم الشرعي هو خطاب الله تعالى المتعلق بأفعال المكلفين، طلبًا أو تخييرًا أو وضعًا. وينقسم إلى قسمين رئيسين: الحكم التكليفي، وهو ما يقتضي طلب فعل أو ترك أو التخيير بينهما، وله خمس مراتب: الواجب، والمندوب، والمباح، والمكروه، والحرام. والحكم الوضعي، وهو ما جعله الشارع علامة على حكم تكليفي أو شرطًا له أو مانعًا منه، كجعل زوال الشمس سببًا لوجوب صلاة الظهر، والطهارة شرطًا لصحتها.', 1),
    (v_lesson, 'examples', 'مثال جامع بين النوعين', 'وجوب صلاة الظهر حكم تكليفي، أما جعل دخول وقت الظهر سببًا لهذا الوجوب، وجعل الطهارة شرطًا لصحة الصلاة، فهما من الحكم الوضعي المرتبط بالحكم التكليفي ذاته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الوجيز في أصول الفقه — د. وهبة الزحيلي', 1);
  END IF;

  -- 2) الأدلة المتفق عليها
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ceebb50c-b9dd-46df-8cbf-f9f5f4e46f9f' AND title='الأدلة المتفق عليها: القرآن والسنة والإجماع والقياس') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأدلة المتفق عليها: القرآن والسنة والإجماع والقياس', 'تعريف موجز بالأدلة الشرعية الأربعة المتفق على حجيتها بين جمهور الأصوليين', 'ceebb50c-b9dd-46df-8cbf-f9f5f4e46f9f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الأدلة الأربعة المتفق عليها', 'اتفق جمهور الأصوليين على أن الأدلة الشرعية الأساسية أربعة: القرآن الكريم، وهو المصدر الأول والأصل الذي يُرَدُّ إليه كل خلاف؛ والسنة النبوية، وهي البيان العملي والقولي لما أجمله القرآن أو استقل بتشريعه؛ والإجماع، وهو اتفاق مجتهدي الأمة في عصر من العصور على حكم شرعي؛ والقياس، وهو إلحاق واقعة لا نص فيها بواقعة ورد فيها نص لاشتراكهما في العلة.', 1),
    (v_lesson, 'examples', 'دليل الأمر بطاعة الله والرسول وأولي الأمر', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنكُمْ فَإِن تَنَازَعْتُمْ فِي شَيْءٍ فَرُدُّوهُ إِلَى اللَّهِ وَالرَّسُولِ﴾ (النساء: 59)، وهي الآية التي استدل بها الأصوليون على أن الرد عند التنازع يكون إلى القرآن (رد إلى الله) والسنة (رد إلى الرسول)، وهما الأصلان اللذان تُبنى عليهما بقية الأدلة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول الفقه — محمد أبو زهرة', 1);
  END IF;

  -- 3) الأدلة المختلف فيها
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8c8df5ee-0d97-40e9-a278-f74996768220' AND title='الأدلة المختلف فيها: الاستحسان وقول الصحابي وشرع من قبلنا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأدلة المختلف فيها: الاستحسان وقول الصحابي وشرع من قبلنا', 'تعريف موجز بالأدلة الشرعية التي اختلف الأصوليون في حجيتها', '8c8df5ee-0d97-40e9-a278-f74996768220', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'معنى الأدلة المختلف فيها', 'هي الأدلة التي اختلف الأصوليون في الاحتجاج بها استقلالاً، مع كونها معتبرة عند بعض المذاهب دون بعض، ومن أبرزها: الاستحسان، وهو العدول عن قياس ظاهر إلى حكم آخر لدليل أقوى يقتضيه؛ وقول الصحابي فيما لا مجال للرأي فيه؛ وشرع من قبلنا مما ورد في شرائع الأنبياء السابقين ولم يرد ما ينسخه في شرعنا؛ إضافة إلى الاستصحاب والمصالح المرسلة وسد الذرائع والعرف، وهي أدلة تفصيلية لكل منها بحث مستقل.', 1),
    (v_lesson, 'examples', 'مثال الاستحسان عند الحنفية', 'من أمثلة الاستحسان: جواز دخول الحمام العام بأجرة مجهولة المدة والماء المستهلك، استحسانًا لحاجة الناس ورفعًا للحرج، مع أن قياس عقد الإجارة الظاهر يقتضي منع ذلك لجهالة العوض والمعقود عليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الوجيز في أصول الفقه — د. وهبة الزحيلي', 1);
  END IF;

  -- 4) دلالات الألفاظ
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='05d1fcba-c9bc-4ca9-bf1a-75a946b25436' AND title='دلالات الألفاظ: المنطوق والمفهوم وأقسامهما') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('دلالات الألفاظ: المنطوق والمفهوم وأقسامهما', 'تعريف موجز بكيفية دلالة الألفاظ الشرعية على معانيها وأقسام هذه الدلالة', '05d1fcba-c9bc-4ca9-bf1a-75a946b25436', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'المنطوق والمفهوم', 'تنقسم دلالة اللفظ على المعنى إلى منطوق، وهو ما دل عليه اللفظ في محل النطق، وينقسم إلى دلالة العبارة (ما يُفهم من سياق الكلام مباشرة)، ودلالة الإشارة (ما يلزم من اللفظ لزومًا غير مقصود ابتداءً)، ودلالة الاقتضاء (ما لا يستقيم الكلام إلا بتقدير محذوف)، ودلالة النص أو الإيماء (التعليل المفهوم من السياق). وإلى مفهوم، وهو ما دل عليه اللفظ لا في محل النطق، وينقسم إلى مفهوم موافقة ومفهوم مخالفة.', 1),
    (v_lesson, 'examples', 'مثال دلالة الاقتضاء', 'قال تعالى حكاية عن إخوة يوسف: ﴿وَاسْأَلِ الْقَرْيَةَ الَّتِي كُنَّا فِيهَا وَالْعِيرَ الَّتِي أَقْبَلْنَا فِيهَا﴾ (يوسف: 82)، فالقرية لا تُسأل حقيقة، فلا بد من تقدير محذوف هو ''أهل القرية''؛ وهذا مثال على دلالة الاقتضاء التي لا يستقيم الكلام بدونها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'روضة الناظر — ابن قدامة', 1);
  END IF;

  -- 5) النسخ
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='563f18ff-5e01-44f5-bd1d-2f771fc588e8' AND title='النسخ في أصول الفقه: تعريفه وشروطه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('النسخ في أصول الفقه: تعريفه وشروطه', 'تعريف موجز للنسخ عند الأصوليين وشروط تحققه', '563f18ff-5e01-44f5-bd1d-2f771fc588e8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف النسخ وشروطه', 'النسخ في اصطلاح الأصوليين: رفع الشارع حكمًا شرعيًا سابقًا بدليل شرعي متأخر عنه. ويشترط لتحققه: أن يكون الحكم المنسوخ شرعيًا، وأن يكون دليل النسخ متأخرًا في الورود عن الحكم المنسوخ، وأن يتعذر الجمع بين الحكمين لتعارضهما، وأن يكون كلا الحكمين خطابًا شرعيًا لا خبرًا.', 1),
    (v_lesson, 'examples', 'مثال منسوخ: عدة المتوفى عنها زوجها', 'كانت عدة المتوفى عنها زوجها حولاً كاملاً كما في قوله تعالى: ﴿وَالَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِّأَزْوَاجِهِم مَّتَاعًا إِلَى الْحَوْلِ﴾ (البقرة: 240)، ثم نُسخ هذا الحكم بقوله تعالى: ﴿وَالَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَاجًا يَتَرَبَّصْنَ بِأَنفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا﴾ (البقرة: 234)، فصارت العدة أربعة أشهر وعشرًا.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الوجيز في أصول الفقه — د. وهبة الزحيلي', 1);
  END IF;

  -- 6) التعارض والترجيح
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='3fc93412-7fdd-43e0-9d69-028bed761301' AND title='التعارض والترجيح: طرق دفع تعارض الأدلة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التعارض والترجيح: طرق دفع تعارض الأدلة', 'تعريف موجز للتعارض الظاهري بين الأدلة وطرق العلماء في دفعه', '3fc93412-7fdd-43e0-9d69-028bed761301', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'معنى التعارض وطرق دفعه', 'التعارض عند الأصوليين هو تقابل دليلين متكافئين في القوة بحيث يقتضي كل منهما خلاف ما يقتضيه الآخر في المسألة ذاتها، وهو تعارض ظاهري لا حقيقي، إذ لا يمكن أن يتعارض دليلان صحيحان في نفس الأمر. وقد رتّب الأصوليون طرق دفعه على الترتيب التالي: الجمع بين الدليلين إن أمكن، فإن تعذر فالنسخ إن عُلم المتأخر منهما، فإن جُهل التاريخ فالترجيح بمرجّح معتبر، فإن تعذر كل ذلك فالتوقف عن العمل بأيهما حتى يظهر المرجّح.', 1),
    (v_lesson, 'examples', 'مثال الترجيح بالخاص على العام', 'من أشهر المرجّحات عند تعارض دليلين: تقديم الدليل الخاص على الدليل العام عند تعذر الجمع بينهما؛ لأن دلالة الخاص على أفراده أقوى من دلالة العام عليها، فيُبنى العام على الخاص ولا يُلغى أحدهما بالكلية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إرشاد الفحول — الإمام محمد بن علي الشوكاني', 1);
  END IF;

  -- 7) الاجتهاد والتقليد والفتوى
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4149e33f-998c-4c9f-a83d-41d2b903199e' AND title='الاجتهاد والتقليد والفتوى: تعريفاتها والفروق بينها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الاجتهاد والتقليد والفتوى: تعريفاتها والفروق بينها', 'تعريف موجز بالاجتهاد وشروط المجتهد، والتقليد، والفتوى وعلاقتها بالقضاء', '4149e33f-998c-4c9f-a83d-41d2b903199e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف الاجتهاد والتقليد', 'الاجتهاد هو استفراغ الفقيه الوسع لتحصيل ظن بحكم شرعي، ويشترط في المجتهد معرفة الكتاب والسنة ومواضع الإجماع ومقاصد الشريعة والعربية وأصول الفقه ونحو ذلك مما يُمكّنه من استنباط الأحكام. أما التقليد فهو أخذ قول الغير من غير معرفة دليله، وهو جائز لمن لم تتوفر فيه أهلية الاجتهاد.', 1),
    (v_lesson, 'examples', 'الفرق بين الفتوى والقضاء', 'الفتوى إخبار عن الحكم الشرعي من غير إلزام، يصدرها المفتي بناءً على سؤال المستفتي دون سلطة تنفيذية؛ أما القضاء فهو فصل في الخصومة بحكم مُلزم يصدره القاضي بولاية شرعية، فالفتوى إخبار والقضاء إلزام.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول الفقه — محمد أبو زهرة', 1);
  END IF;

  -- 8) تحقيق المناط
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='da577479-baa0-49c2-ad51-4c1bc2f991ea' AND title='تحقيق المناط: تعريفه والفرق بينه وبين تخريج المناط وتنقيحه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تحقيق المناط: تعريفه والفرق بينه وبين تخريج المناط وتنقيحه', 'تعريف موجز لتحقيق المناط وعلاقته بتخريج المناط وتنقيحه في القياس', 'da577479-baa0-49c2-ad51-4c1bc2f991ea', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف تحقيق المناط', 'تحقيق المناط هو النظر في تحقق العلة المعروفة السبب في آحاد الصور والجزئيات؛ أي أن العلة معلومة سلفًا من نص أو إجماع أو تخريج، وإنما يبحث المجتهد في وجودها في الفرع المعيّن الذي يُراد إلحاقه بالأصل.', 1),
    (v_lesson, 'examples', 'الفرق بينه وبين تخريج المناط وتنقيحه', 'يختلف تحقيق المناط عن تخريج المناط (استخراج العلة من نص لم تُذكر فيه) وتنقيح المناط (تجريد العلة مما لا أثر له من الأوصاف)؛ فتحقيق المناط لا يتعلق باستنباط العلة ذاتها بل بتطبيقها على واقعة بعينها، كالبحث عن مدى توفر شرط ''العدالة'' المعلومة العلة في شاهد معيّن قبل قبول شهادته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'إرشاد الفحول — الإمام محمد بن علي الشوكاني', 1);
  END IF;

  -- 9) القواعد الأصولية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='dc2107c2-a209-4a24-9afd-65f5442b4ca0' AND title='القواعد الأصولية: تعريفها وأشهر أمثلتها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('القواعد الأصولية: تعريفها وأشهر أمثلتها', 'تعريف موجز بالقواعد الأصولية والفرق بينها وبين القواعد الفقهية', 'dc2107c2-a209-4a24-9afd-65f5442b4ca0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف القاعدة الأصولية', 'القاعدة الأصولية هي حكم كلي ينطبق على جزئيات كثيرة يُستفاد منها كيفية استنباط الأحكام من أدلتها، وتختلف عن القاعدة الفقهية التي تتعلق بأحكام فقهية فرعية متعددة الأبواب؛ فموضوع القاعدة الأصولية طرق الاستدلال ذاتها، لا الأحكام الفرعية المستنبطة.', 1),
    (v_lesson, 'examples', 'أمثلة من أشهر القواعد الأصولية', 'من أشهر القواعد الأصولية: ''الأمر المطلق يقتضي الوجوب ما لم تصرفه قرينة''، و''النهي يقتضي التحريم ما لم تصرفه قرينة''، و''الأصل في الأشياء الإباحة حتى يقوم دليل التحريم''، و''العبرة بعموم اللفظ لا بخصوص السبب''، و''لا اجتهاد مع وجود النص الصريح''.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الوجيز في أصول الفقه — د. وهبة الزحيلي', 1);
  END IF;

